import { useEvent } from '@kyokuya/react-hooks'
import type { SelectChangeEvent } from '@mui/material'
import { MenuItem, Select } from '@mui/material'
import React from 'react'
import type { IFormItemRendererProps } from './types'

type IEnum = string | number
export type IFormItemEnumProps<T extends IEnum> = IFormItemRendererProps<T>

interface IParams<T extends IEnum> {
  choices: Record<T, React.ReactNode> | T[]
  componentName?: string
  normalize?(data: string): T
}

export const createFormItemEnum = <T extends IEnum>({
  choices,
  componentName,
  normalize = (data: string) => data as T,
}: IParams<T>): React.FC<IFormItemEnumProps<T>> => {
  const menuItems = Array.isArray(choices)
    ? choices.map((key: T) => (
        <MenuItem key={key} value={key}>
          {key}
        </MenuItem>
      ))
    : (Object.keys(choices) as T[]).map((key: T) => (
        <MenuItem key={key} value={key}>
          {choices[key]}
        </MenuItem>
      ))

  const FormItemEnum: React.FC<IFormItemEnumProps<T>> = props => {
    const events = {
      onChange: useEvent((e: SelectChangeEvent<T>): void => {
        const nextValue = normalize(e.target.value as string) as T
        props.onChange(nextValue)
      }),
    }

    return (
      <Select<T>
        variant="standard"
        required={props.required}
        disabled={props.disabled}
        value={props.value}
        onChange={events.onChange}
      >
        {menuItems}
      </Select>
    )
  }

  FormItemEnum.displayName = componentName ?? 'FormItemEnum'
  return FormItemEnum
}
