import { deepAssign } from '@kyokuya/core-util'
import type { Theme } from '@yozora/core-react-theme'
import { defaultSiteState } from './config'

export interface ISiteState {
  author: {
    name: string
    motto: string
    github: string
    rss: string
    home: string
  }
  copyright: {
    date: string
  }
  title: string
  description: string
  siteUrl: string
  preference: {
    theme: Theme
    octotreePined: boolean
    octotreeWidth: number
  }
}

export type ISiteData = ISiteState

export function initSiteState(
  customizedData?: Partial<ISiteData> | null,
  baseState: Readonly<ISiteState> = defaultSiteState,
): ISiteState {
  return deepAssign(baseState, customizedData ?? {})
}
