import type { CSSInterpolation } from '@emotion/css'
import { css } from '@emotion/css'
import type { RGBColor } from 'react-color'

export type IColor = RGBColor

export interface IColorOrImage {
  prefer: 'color' | 'image'
  color?: IColor
  imageUrl?: string
}

export function mergeStyleSets<T extends Record<string, CSSInterpolation>>(
  classes: Readonly<T>,
): { [K in keyof T]: string } {
  const result = {} as unknown as Record<keyof T, string>
  for (const key of Object.keys(classes)) {
    result[key as keyof T] = css(classes[key])
  }
  return result
}

export const calcCssBackground = (background: IColorOrImage): string | undefined => {
  switch (background.prefer) {
    case 'color':
      if (background.color != null) return calcCssColor(background.color)
      break
    case 'image':
      if (background.imageUrl) return fromImage(background.imageUrl)
      break
    default:
  }

  if (background.imageUrl) return fromImage(background.imageUrl)
  if (background.color != null) return calcCssColor(background.color)
  return undefined

  function fromImage(imageUrl: string): string {
    return `url(${imageUrl})`
  }
}

export const calcCssColor = (color: IColor): string => {
  const { r, g, b, a } = color
  return `rgba(${r}, ${g}, ${b}, ${a})`
}
