import { BackgroundPicker } from '@kyokuya/core-component'
import type { IColorOrImage } from '@kyokuya/core-util'
import { calcCssBackground, mergeStyleSets } from '@kyokuya/core-util'
import { useEvent } from '@kyokuya/react-hooks'
import React from 'react'
import type { IFormItemRendererProps } from './types'

export type IFormItemBackgroundProps = IFormItemRendererProps<IColorOrImage>

interface IParams {
  componentName?: string
}

export const createFormItemBackground = ({
  componentName,
}: IParams): React.FC<IFormItemBackgroundProps> => {
  const FormItemBackground: React.FC<IFormItemBackgroundProps> = props => {
    const { value: background, disabled } = props
    const [pickerVisible, setPickerVisible] = React.useState<boolean>(false)

    const events = {
      onTogglePickerVisible: useEvent(() => {
        if (disabled) return
        setPickerVisible(v => !v)
      }),
      onBackgroundChange: useEvent((nextBackground: IColorOrImage): void => {
        if (disabled) return
        props.onChange(nextBackground)
      }),
    }

    const classes = useStyles(background, disabled)
    return (
      <div className={classes.container}>
        <div className={classes.swatch} onClick={events.onTogglePickerVisible}>
          <div className={classes.colorSquare} />
        </div>
        <BackgroundPicker
          className={classes.picker}
          visible={pickerVisible}
          background={background}
          onVisibleChange={setPickerVisible}
          onBackgroundChange={events.onBackgroundChange}
        />
      </div>
    )
  }

  FormItemBackground.displayName = componentName ?? 'FormItemBackground'
  return FormItemBackground
}

const useStyles = (background: IColorOrImage, disabled: boolean | undefined) => {
  return mergeStyleSets({
    container: {
      display: 'flex',
      alignItems: 'center',
    },
    swatch: {
      display: 'inline-block',
      padding: 3,
      border: '1px solid rgba(0,0,0,.2)',
      borderRadius: '1px',
      background: '#fff',
      cursor: disabled ? 'default' : 'pointer',
    },
    colorSquare:
      background.prefer === 'image'
        ? {
            width: 32,
            height: 32,
            borderRadius: 2,
            background: calcCssBackground(background),
            backgroundSize: 'cover',
          }
        : {
            width: 32,
            height: 12,
            borderRadius: 2,
            background: calcCssBackground(background),
            backgroundSize: 'cover',
          },
    picker: {
      '&&': {
        left: 30,
      },
    },
  })
}
