import { createUseSelectableContext } from '@kyokuya/react-hooks'
import { createPersistProvider } from '@kyokuya/react-storage'
import React from 'react'
import type { ISiteAction } from './action'
import { siteReducer } from './reducer'
import type { ISiteData, ISiteState } from './state'
import { initSiteState } from './state'

export interface ISiteContext {
  state: ISiteState
  dispatch: React.Dispatch<ISiteAction | ISiteAction[]>
}

const SiteContextType = React.createContext<ISiteContext>({
  state: initSiteState(),
  dispatch: () => {
    throw new Error('[SiteContextType] dispatch is not available yet.')
  },
})

export const SiteContextProvider = createPersistProvider<ISiteState, ISiteAction, ISiteData>({
  ContextType: SiteContextType,
  ContextName: 'SiteContext',
  initState: initSiteState,
  reducer: siteReducer,
  serialize: data => data,
})

export const useSiteContext = createUseSelectableContext(SiteContextType)
