import React from 'react'

export function useHeaveState<S>(
  initialState: S | (() => S),
): [S, React.Dispatch<React.SetStateAction<Partial<S>>>] {
  const [state, setState] = React.useState<S>(initialState)
  const patchState = React.useCallback(
    (partialState: Partial<S> | ((prevState: S) => Partial<S>)): void => {
      setState(prevState => ({
        ...prevState,
        ...(typeof partialState === 'function' ? partialState(prevState) : partialState),
      }))
    },
    [],
  )
  return [state, patchState]
}
