import { cx } from '@emotion/css'
import type { IColorOrImage } from '@kyokuya/core-util'
import { mergeStyleSets } from '@kyokuya/core-util'
import { useEvent } from '@kyokuya/react-hooks'
import { Button, FormControl, FormControlLabel, Radio, RadioGroup } from '@mui/material'
import { unstable_useId as useId } from '@mui/utils'
import React from 'react'
import type { ColorResult } from 'react-color'
import { SketchPicker } from 'react-color'

export interface IBackgroundPickerProps {
  visible: boolean
  background: IColorOrImage
  className?: string
  onVisibleChange(visible: boolean): void
  onBackgroundChange(background: IColorOrImage): void
}

export const BackgroundPicker: React.FC<IBackgroundPickerProps> = props => {
  const { background, onBackgroundChange, onVisibleChange } = props

  const events = {
    onPickerClicked: useEvent((e: React.MouseEvent): void => e.stopPropagation()),
    onClosePicker: useEvent((e: React.MouseEvent): void => onVisibleChange(false)),
    onPreferChange: useEvent((_event: React.ChangeEvent<HTMLInputElement>, value: string): void => {
      const nextBackground: IColorOrImage = {
        prefer: value as 'color' | 'image',
        imageUrl: background.imageUrl,
        color: background.color,
      }
      onBackgroundChange(nextBackground)
    }),
    onColorChange: useEvent((color: ColorResult): void => {
      const nextBackground: IColorOrImage = {
        prefer: 'color',
        imageUrl: background.imageUrl,
        color: color.rgb,
      }
      onBackgroundChange(nextBackground)
    }),
    onImageChange: (event: React.ChangeEvent<HTMLInputElement>): void => {
      const files = event.target.files
      if (files !== null) {
        const reader = new FileReader()
        reader.readAsDataURL(files[0])
        reader.onload = e => {
          const imageUrl = e.target?.result
          if (imageUrl != null) {
            const nextBackground: IColorOrImage = {
              prefer: 'image',
              color: background.color,
              imageUrl: String(imageUrl),
            }
            onBackgroundChange(nextBackground)
          }
        }
      }
    },
  }

  const classes = useStyles(props.visible, background.prefer)
  const imageInputId = useId()

  return (
    <div className={cx(classes.popover, props.className)} onClick={events.onPickerClicked}>
      <div className={classes.cover} onClick={events.onClosePicker} />
      <div className={classes.backgroundPicker}>
        <div key="prefer" className={classes.backgroundPrefer}>
          <FormControl style={{ display: 'flex', justifyContent: 'center' }}>
            <RadioGroup
              className={classes.backgroundRadioGroup}
              value={background.prefer}
              onChange={events.onPreferChange}
            >
              <FormControlLabel value="color" control={<Radio />} label="color" />
              <FormControlLabel value="image" control={<Radio />} label="image" />
            </RadioGroup>
          </FormControl>
        </div>
        <div key="picker">
          <div
            key="color-picker"
            className={classes.colorPickerWrapper}
            onDoubleClick={events.onClosePicker}
          >
            <SketchPicker
              className={classes.colorPicker}
              color={background.color}
              onChange={events.onColorChange}
            />
          </div>
          <div key="image-picker" className={classes.imagePickerWrapper}>
            <input
              type="file"
              accept="image/*"
              id={imageInputId}
              style={{ display: 'none' }}
              multiple={false}
              onChange={events.onImageChange}
            />
            <label htmlFor={imageInputId}>
              <Button className={classes.imageUploadBtn} variant="contained" component="span">
                <img alt="background" src={background.imageUrl} />
              </Button>
            </label>
          </div>
        </div>
      </div>
    </div>
  )
}

const useStyles = (visible: boolean, prefer: 'color' | 'image') => {
  return React.useMemo(
    () =>
      mergeStyleSets({
        popover: {
          position: 'absolute',
          zIndex: 20,
          top: 20,
          display: visible ? 'block' : 'none',
          visibility: visible ? 'visible' : 'hidden',
        },
        cover: {
          position: 'fixed',
          top: '0px',
          right: '0px',
          bottom: '0px',
          left: '0px',
          cursor: 'default',
        },
        backgroundPicker: {
          display: 'flex',
          flexDirection: 'column',
          minWidth: 220,
          border: '1px solid #e6e6e6',
          borderRadius: 4,
          boxShadow: 'rgba(0, 0, 0, 0.15) 0px 0px 0px 1px, rgba(0, 0, 0, 0.15) 0px 8px 16px',
          background: '#fff',
        },
        backgroundPrefer: {
          flex: '0 0 auto',
          borderBottom: '1px solid rgba(0, 0, 0, 0.15)',
          userSelect: 'none',
        },
        backgroundRadioGroup: {
          '&&': {
            display: 'flex',
            flexDirection: 'row',
            justifyContent: 'center',
          },
        },
        imagePickerWrapper: {
          boxSizing: 'border-box',
          display: prefer === 'image' ? 'flex' : 'none',
          justifyContent: 'center',
          alignItems: 'center',
          width: 220,
          height: 220,
          img: {
            display: 'inline-block',
            width: 200,
            height: 200,
          },
        },
        colorPickerWrapper: {
          display: prefer === 'color' ? 'block' : 'none',
        },
        colorPicker: {
          '&&': {
            border: 'none !important',
            borderRadius: '0px !important',
            boxShadow: 'none !important',
          },
        },
        imageUploadBtn: {
          '&&': {
            background: 'none',
            padding: 0,
            margin: 0,
          },
        },
      }),
    [visible, prefer],
  )
}
