import { noEffectAssign } from '@kyokuya/core-util'
import type React from 'react'
import type { ISiteAction } from './action'
import { SiteActionType } from './constant'
import type { ISiteState } from './state'

export const siteReducer: React.Reducer<ISiteState, ISiteAction> = (prevState, action) => {
  switch (action.type) {
    case SiteActionType.PATCH_PREFERENCE:
      return { ...prevState, preference: noEffectAssign(prevState.preference, action.payload) }
    default:
      return prevState
  }
}
