import { useSyncState } from '@guanghechen/react-hooks'
import { useEvent } from '@kyokuya/react-hooks'
import { TextField } from '@mui/material'
import React from 'react'
import type { IFormItemRendererProps } from './types'

export type IFormItemStringProps = IFormItemRendererProps<string>

interface IParams {
  componentName?: string
}

export const createFormItemString = ({
  componentName,
}: IParams): React.FC<IFormItemStringProps> => {
  const FormItemString: React.FC<IFormItemStringProps> = props => {
    const [value, setValue] = useSyncState<string>(props.value)
    const events = {
      onChange: useEvent((e: React.ChangeEvent<HTMLInputElement>): void => {
        setValue(e.target.value)
      }),
      onBlur: useEvent((): void => {
        props.onChange(value)
      }),
    }

    return (
      <TextField
        variant="standard"
        disabled={props.disabled}
        required={props.required}
        value={value}
        onChange={events.onChange}
        onBlur={events.onBlur}
      />
    )
  }

  FormItemString.displayName = componentName ?? 'FormItemString'
  return FormItemString
}
