import { cx } from '@emotion/css'
import { useEvent } from '@guanghechen/react-hooks'
import { mergeStyleSets } from '@kyokuya/core-util'
import type { PortalProps } from '@mui/material'
import { Button, Dialog, DialogActions, DialogContent } from '@mui/material'
import isEqual from 'fast-deep-equal/react'
import React from 'react'
import type { IFormClasses } from './Form'
import { Form } from './Form'
import type { IFormItems } from './types'

export type IFormDialogClasses = IFormClasses & { dialog?: string }

export interface IFormDialogProps<D> {
  initialData: D
  factoryData?: D
  items: IFormItems<D>
  itemsOrder?: Array<keyof D>
  container?: PortalProps['container']
  classes?: IFormDialogClasses
  isResetAvailable?: boolean
  onSave(data: D): void
  onDiscard(data: D): void
  onReset?(): void
  onRealTimeChange?(data: D): void
}

export function FormDialog<D>(props: IFormDialogProps<D>): React.ReactElement {
  const [initialData] = React.useState<D>(props.initialData)
  const [state, setState] = React.useState<D>(initialData)

  const factoryData: D = props.factoryData ?? initialData
  const isNoChangeWithInitialData: boolean = isEqual(initialData, state)
  const isNoChangeWithFactoryData: boolean = isEqual(factoryData, state)
  const isResetAvailable: boolean = (props.isResetAvailable ?? true) && !isNoChangeWithFactoryData

  const events = {
    onConfirm: useEvent((): void => props.onSave(state)),
    onDiscard: useEvent((): void => props.onDiscard(initialData)),
    onChange: useEvent((data: Partial<D>): void => {
      const nextState: D = { ...state, ...data }
      setState(nextState)
      props.onRealTimeChange?.(nextState)
    }),
    onReset: useEvent((): void => {
      const nextState: D = { ...factoryData }
      setState(nextState)
      if (props.onReset != null) props.onReset()
      else props.onRealTimeChange?.(nextState)
    }),
    onClose: useEvent((): void => {
      if (isNoChangeWithInitialData) props.onDiscard(initialData)
    }),
  }

  const beforeunloadRef = React.useRef(events.onDiscard)
  React.useEffect(() => {
    const beforeunload = (): void => beforeunloadRef.current()
    window.addEventListener('beforeunload', beforeunload)
    return () => window.removeEventListener('beforeunload', beforeunload)
  }, [])

  const itemsOrder = props.itemsOrder ?? (Object.keys(props.items) as Array<keyof D>)
  return (
    <Dialog
      aria-labelledby="edit-player"
      container={props.container}
      open={true}
      onClose={events.onClose}
    >
      <DialogContent className={cx(classes.dialog, props.classes?.dialog)}>
        <Form<D>
          data={state}
          items={props.items}
          itemsOrder={itemsOrder}
          classes={props.classes}
          onChange={events.onChange}
        />
      </DialogContent>
      <DialogActions>
        {props.factoryData != null && (
          <Button color="inherit" disabled={!isResetAvailable} onClick={events.onReset}>
            Reset
          </Button>
        )}
        <Button color="inherit" onClick={events.onDiscard}>
          Discard
        </Button>
        <Button color="primary" disabled={isNoChangeWithInitialData} onClick={events.onConfirm}>
          Save
        </Button>
      </DialogActions>
    </Dialog>
  )
}

const classes = mergeStyleSets({
  dialog: {
    minWidth: 240,
    minHeight: 300,
  },
  wakeBtn: {
    '> svg': {
      width: 18,
      height: 18,
    },
  },
})
