import { JsonType } from './constant'
import type { DeepPartial } from './type'

export const removeUndefinedValues = <T>(data: Readonly<T>): Partial<T> => {
  const result: Partial<T> = {}
  for (const key of Object.keys(data)) {
    const value = data[key]
    if (value !== undefined) result[key] = value
  }
  return result
}

/**
 * !!! Undefined values from the patchPayload will be ignored.
 *
 * Shallow assign patchPayload into prevState. (Pure function)
 *
 * @param prevState
 * @param patchPayload
 * @returns
 */
export const noEffectAssign = <T>(prevState: T, patchPayload: Partial<T> | undefined | void): T => {
  if (patchPayload === undefined || prevState === patchPayload) return prevState

  const _type1 = getJsonType(prevState)
  const _type2 = getJsonType(patchPayload)
  if (_type1 !== _type2 || _type1 !== JsonType.OBJECT) return patchPayload as T

  let isNoChange = true
  let nextState: T = prevState
  for (const key of Object.keys(patchPayload)) {
    const value = patchPayload[key]
    if (value === prevState[key] || value === undefined) continue
    if (isNoChange) {
      isNoChange = false
      nextState = { ...prevState }
    }
    nextState[key] = value
  }
  return nextState
}

export const deepAssign = <T>(
  prevState: Readonly<T>,
  patchPayload: DeepPartial<T> | undefined,
): T => {
  if (patchPayload === undefined || prevState === patchPayload) return prevState

  const _type1 = getJsonType(prevState)
  const _type2 = getJsonType(patchPayload)
  if (_type1 !== JsonType.OBJECT) return patchPayload as T
  if (_type1 !== _type2) return prevState
  return update(prevState, patchPayload)

  function update<S>(draft: S, payload: DeepPartial<S>): S {
    let isNoChange = true
    let nextState: S = draft
    for (const key of Object.keys(payload)) {
      const value1 = payload[key]
      if (value1 === undefined) continue

      const value0 = draft[key]
      const _type_0 = getJsonType(value0)
      const _type_1 = getJsonType(value1)
      const nextValue =
        _type_0 === _type_1 && _type_0 === JsonType.OBJECT ? update(value0, value1) : value1
      if (nextValue === value0) continue

      if (isNoChange) {
        isNoChange = false
        nextState = { ...draft }
      }
      nextState[key] = nextValue
    }
    return nextState
  }
}

export const getJsonType = (obj: unknown): JsonType => {
  if (obj === null) return JsonType.NULL
  switch (typeof obj) {
    case 'boolean':
      return JsonType.BOOLEAN
    case 'number':
      return JsonType.NUMBER
    case 'object':
      return Array.isArray(obj) ? JsonType.ARRAY : JsonType.OBJECT
    case 'string':
      return JsonType.STRING
    default:
      return JsonType.UNKNOWN
  }
}

export const pick = <T extends Record<string, any>>(
  data: T,
  keys?: ReadonlyArray<keyof T>,
): Partial<T> => {
  if (keys === undefined) return data
  const result: Partial<T> = {}
  for (const key of keys) result[key] = data[key]
  return result
}
